        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new SpreadExchPrintMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[SpreadExchPrintMessage](sbeTemplateId=");
            builder.Append(SpreadExchPrintMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(SpreadExchPrintMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != SpreadExchPrintMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(SpreadExchPrintMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != SpreadExchPrintMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(SpreadExchPrintMessage.BlockLength);
            builder.Append("):");

            builder.Append("RequestID=");
            builder.Append(this.RequestID);
            builder.Append('|');
            builder.Append("Count=");
            builder.Append(this.Count);
            builder.Append('|');
            builder.Append("Prints=[");
            var prints = this.Prints;
            if (prints.Count > 0)
            {
                var first = true;
                while (prints.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    prints.Next().BuildString(builder);
                }
            }
            builder.Append("]");

            this.Limit = originalLimit;

        }
